mapper.select:
SELECT 
	id,
	user_id,
	category_id,
	amount,
	type,
	memo,
	`date`
FROM
	`transaction`
WHERE user_id = #{userId}


	AND `date` >= #{startDate}  



	AND `date` <= #{endDate}    



	AND type = #{type}



	AND category_id = #{categoryId}


ORDER BY `date` DESC, id DESC

mapper.update:
UPDATE `transaction`
SET category_id = #{categoryId},
    amount = #{amount},
    type = #{type},
    memo = #{memo},
    `date` = #{date}
WHERE id = #{id}    
  AND user_id = #{userId}

mapper.delete:
DELETE FROM `transaction`
WHERE id = #{id}
  AND user_id = #{userId}
